-- Morton3D corridor lookup (interval decomposition)
-- key_u64 is bit-interleaved (local_x, local_y, hbin).
-- A box query in Morton space decomposes into multiple (min, max) ranges.
-- Fewer ranges = better row-group pruning.
--
-- NOTE: The WHERE clause below is generated by morton3d.key_ranges_from_cells().
--       This template shows the pattern; actual ranges differ per corridor.

SELECT DISTINCT osm_id
FROM read_parquet('data/parquet/occupancy_morton3d.parquet')
WHERE xy_z         = $xy_z
  AND vertical_bin_m = $vertical_bin_m
  AND (
      (key_u64 BETWEEN $range0_min AND $range0_max)
   OR (key_u64 BETWEEN $range1_min AND $range1_max)
   -- … more ranges as needed
  );
